    public var config: RunConfig
    public var daemonSocket: String
    public var timeLimitSecs: UInt64?
    public var terminalSize: TerminalSize?

    nonisolated public init(command: [String], cwd: String, env: [LaunchEnvVar], config: RunConfig, daemonSocket: String, timeLimitSecs: UInt64?, terminalSize: TerminalSize?) {
        self.command = command
        self.cwd = cwd
        self.env = env
        self.config = config
        self.daemonSocket = daemonSocket
        self.timeLimitSecs = timeLimitSecs
        self.terminalSize = terminalSize
    }
}

