// MARK: - Shared Encoders

nonisolated internal func encodeTopSort(_ value: TopSort, into buffer: inout ByteBuffer) {
    switch value {
    case .bySelf:
        encodeVarint(UInt64(0), into: &buffer)
    case .byTotal:
        encodeVarint(UInt64(1), into: &buffer)
    }
}

nonisolated internal func encodeTimeRange(_ value: TimeRange, into buffer: inout ByteBuffer) {
    encodeVarint(value.startNs, into: &buffer)
    encodeVarint(value.endNs, into: &buffer)
}

nonisolated internal func encodeSymbolRef(_ value: SymbolRef, into buffer: inout ByteBuffer) {
    encodeOption(value.functionName, into: &buffer, encoder: { val, buf in encodeString(val, into: &buf) })
    encodeOption(value.binary, into: &buffer, encoder: { val, buf in encodeString(val, into: &buf) })
}

nonisolated internal func encodeLiveFilter(_ value: LiveFilter, into buffer: inout ByteBuffer) {
    encodeOption(value.timeRange, into: &buffer, encoder: { val, buf in encodeTimeRange(val, into: &buf) })
    encodeVec(value.excludeSymbols, into: &buffer, encoder: { val, buf in encodeSymbolRef(val, into: &buf) })
}

nonisolated internal func encodeViewParams(_ value: ViewParams, into buffer: inout ByteBuffer) {
    encodeOption(value.tid, into: &buffer, encoder: { val, buf in encodeU32(val, into: &buf) })
    encodeLiveFilter(value.filter, into: &buffer)
}

nonisolated internal func encodeOffCpuBreakdown(_ value: OffCpuBreakdown, into buffer: inout ByteBuffer) {
    encodeVarint(value.idleNs, into: &buffer)
    encodeVarint(value.lockNs, into: &buffer)
    encodeVarint(value.semaphoreNs, into: &buffer)
    encodeVarint(value.ipcNs, into: &buffer)
    encodeVarint(value.ioReadNs, into: &buffer)
    encodeVarint(value.ioWriteNs, into: &buffer)
    encodeVarint(value.readinessNs, into: &buffer)
    encodeVarint(value.sleepNs, into: &buffer)
    encodeVarint(value.connectNs, into: &buffer)
    encodeVarint(value.otherNs, into: &buffer)
}

nonisolated internal func encodeTopEntry(_ value: TopEntry, into buffer: inout ByteBuffer) {
    encodeVarint(value.address, into: &buffer)
    encodeOption(value.functionName, into: &buffer, encoder: { val, buf in encodeString(val, into: &buf) })
    encodeOption(value.binary, into: &buffer, encoder: { val, buf in encodeString(val, into: &buf) })
    encodeBool(value.isMain, into: &buffer)
    encodeString(value.language, into: &buffer)
    encodeVarint(value.selfOnCpuNs, into: &buffer)
    encodeVarint(value.totalOnCpuNs, into: &buffer)
    encodeOffCpuBreakdown(value.selfOffCpu, into: &buffer)
    encodeOffCpuBreakdown(value.totalOffCpu, into: &buffer)
    encodeVarint(value.selfPetSamples, into: &buffer)
    encodeVarint(value.totalPetSamples, into: &buffer)
    encodeVarint(value.selfOffCpuIntervals, into: &buffer)
    encodeVarint(value.totalOffCpuIntervals, into: &buffer)
    encodeVarint(value.selfCycles, into: &buffer)
    encodeVarint(value.selfInstructions, into: &buffer)
    encodeVarint(value.selfL1dMisses, into: &buffer)
    encodeVarint(value.selfBranchMispreds, into: &buffer)
    encodeVarint(value.totalCycles, into: &buffer)
    encodeVarint(value.totalInstructions, into: &buffer)
    encodeVarint(value.totalL1dMisses, into: &buffer)
    encodeVarint(value.totalBranchMispreds, into: &buffer)
}

nonisolated internal func encodeTopUpdate(_ value: TopUpdate, into buffer: inout ByteBuffer) {
    encodeVarint(value.totalOnCpuNs, into: &buffer)
    encodeOffCpuBreakdown(value.totalOffCpu, into: &buffer)
    encodeVec(value.entries, into: &buffer, encoder: { val, buf in encodeTopEntry(val, into: &buf) })
}

