    encodeVec(value.strings, into: &buffer, encoder: { val, buf in encodeString(val, into: &buf) })
    encodeOption(value.functionName, into: &buffer, encoder: { val, buf in encodeU32(val, into: &buf) })
    encodeOption(value.binary, into: &buffer, encoder: { val, buf in encodeU32(val, into: &buf) })
